VALUES
  ('social-worker-moex-03850', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作專業需要一套倫理守則，下列敘述何者錯誤？', '["社會工作是一種不具獨占性的專業，需要一套倫理守則來取信於社會", "社會工作服務的案主處於相對不利的地位，需要一套倫理守則來保障案主權益", "社會工作助人過程中涉及許多隱私資料的揭露，需要一套倫理守則來約束相關人員的行為", "面對社會問題的複雜與多變性，社會工作者需要一套倫理守則來進行服務的品質管制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03851', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據社工倫理的義務論，社工倫理有消極和積極的義務，下列何者違反了專業倫理的消極性義 務？', '["社工師租借執照給托兒所收取租照費", "社工師沒有積極協助案主尋找資源", "社工師談自己的事占去太多會談時間", "社工師經常與案主一起出遊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03852', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社福單位工作的社工A發現與自己關係不錯的服務中個案甲在找工作上頻頻碰壁，因此想私下 聘用個案甲到家裡來協助家務，一方面可以提供個案經濟來源，另一方面也降低自己的家務負荷。 社工A可能違背了那一個倫理原則？', '["案主自決原則", "保密原則", "專業界線原則", "真誠原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03853', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是團體工作的要素？', '["目標導向的活動設計", "小型團體（smallgroup）", "強調個別成員的需求滿足", "在系統中的服務輸送"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03854', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '為了個案的需求所成立的任務性團體，下列何者錯誤？', '["社區的長照據點工作小組", "兒少保護個案返家評估的團體決策會議", "學校的性別平等教育委員會", "社會福利服務中心社工員的外部督導團體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03855', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「符號互動論」的敘述，下列何者錯誤？', '["又稱互動論，為社會心理學理論的一支，其最早是黎文（KurtLewin,1946）在芝加哥大學提出 這個理論的概念，又稱「芝加哥社會心理學派」", "符號互動論的基本假設之一是隱含著人類不是典型地對刺激做反應，而是對刺激賦予意義且依 此意義產生行動", "參考團體在符號互動論中的地位相當重要，也對團體工作產生很大的影響", "符號互動論的主要理論概念是社會過程、社會結構和自我身分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03856', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「改變階段的治療模式」的敘述，下列何者錯誤？', '["該模式立基於Prochaska及Diclemente的研究，認為改變不會突然發生，需要花時間與精力， 常用在藥物濫用者的團體治療", "改變的過程，開始於對改變需要發生的未知，這個階段稱之為懵懂期", "對於團體的領導者來說，覺察到改變的階段、決定成員在那一個改變階段，及發展活動以動員 成員前進是非常重要的", "若當事人的心智、身體及社會力量已經組裝好，開始採取改變的步驟，且案主持續維持改變， 此時係處在改變的行動期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03857', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當團體中的每位成員有其不同的個人目標時，可能會發展出「隱藏的議題」，下列敘述何者錯誤？', '["隱藏的議題常會干擾團體的努力，有的極具破壞性，有的較無破壞性", "藉著一開始就清楚說明團體的目標，團體領導者可以極小化隱藏議題的影響", "隱藏的議題導致成員無法貢獻，或表現出阻礙團體活動的言行，就必須面質此成員破壞性行為 的後果", "當面質成員有關隱藏的議題時，應促成信任，並採開放性討論該議題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03858', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體領導的提問技巧，下列何者正確？', '["稜鏡型提問是把別人提出的問題反問所有人，將個別問題廣泛徵求成員觀點，成員的答覆率高", "環型提問是向所有人提出問題，由成員輪流回答，可能會出現從眾效應", "定向型提問是向所有人提出問題，指定一人回答，容易引起抗拒，答覆率低", "廣播型提問是針對普遍性問題觀感徵求成員觀點，答覆率高，可引發思考"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03859', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有許多團體的規範，像是「你應該幫助需要幫助的人」、「每個人都應該有機會說話，沒有人可以 壟斷話題」、「假如有人幫助你，你應該投桃報李」、「不可巧詐」這些規則，請依序選出與上列規 範相對應概念？', '["互惠、共享、公平、社會責任", "共享、公平、社會責任、互惠", "社會責任、共享、互惠、公平", "互惠、社會責任、公平、共享"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
